      <input
        type="text"
        value={room.name}
        onChange={(e) => setRoom({ ...room, name: e.target.value })}
        placeholder="Room Name"
      />
      <input
        type="number"
        value={room.capacity}
        onChange={(e) => setRoom({ ...room, capacity: parseInt(e.target.value) })}
