import random

class ChessBot:
    def __init__(self, depth=3):
        self.depth = depth

    def minimax(self, board, depth, maximizing_player=True):
        if depth == 0 or board.is_game_over():
            return self.evaluate(board), None

        if maximizing_player:
            max_eval = float('-inf')
            move = None
            for move in board.legal_moves:
                board.push(move)
                eval = self.minimax(board, depth - 1, False)[0]
                board.pop()
                if eval > max_eval:
                    max_eval = eval
                    move = move
            return max_eval, move

        else:
            min_eval = float('inf')
            for move in board.legal_moves:
                board.push(move)
                eval = self.minimax(board, depth - 1, True)[0]
                board.pop()
                if eval < min_eval:
                    min_eval = eval
            return min_eval, None

    def evaluate(self, board):
        # Simple evaluation function (can be improved)
        return len(board.legal_moves) - len(board.generate_legal_moves())

    def make_move(self, board):
        _, move = self.minimax(board, self.depth)
        return move

# Example usage:
from chess import Board

bot = ChessBot(depth=3)
board = Board()

while not board.is_game_over():
    print(board)
    if board.turn:
        move = bot.make_move(board)
        board.push(move)
    else:
        board.push(random.choice(list(board.legal_moves)))

print("Game Over!")
```

