    for (int i = 0; i < expression.length(); ++i) {
        if (expression[i] >= 'a' && expression[i] <= 'z') {
            std::string var(1, expression[i]);
            if (variables.find(var) == variables.end()) {
                variables[var] = i;
                coefficients[var] = 1;
            } else {
                coefficients[var]++;
            }
        }
    }

    // Construct the derivative expression
    std::string derivativeExpr;
    for (const auto& var : variables) {
        if (coefficients[var.first] > 1) {
            derivativeExpr += std::to_string(coefficients[var.first]) + " * " + var.first + "^" + std::to_string(coefficients[var.first] - 1) + " + ";
        } else if (coefficients[var.first] == 1) {
            derivativeExpr += var.first + "^" + std::to_string(coefficients[var.first] - 1) + " + ";
        }
    }

    // Remove trailing '+ '
    if (!derivativeExpr.empty() && derivativeExpr.back() == '+' && derivativeExpr[derivativeExpr.length() - 3] == '^') {
        derivativeExpr.pop_back();
        derivativeExpr.pop_back();
    }

    return derivativeExpr;
}

